62	  <body style="font-family:system-ui;display:flex;align-items:center;justify-content:center;height:100vh;margin:0;background:#fafafa">
63	    <div style="text-align:center">
64	      <div style="font-size:48px;margin-bottom:16px">&#10003;</div>
65	      <h1 style="margin:0 0 8px">Connected to ${providerName}!</h1>
66	      <p style="color:#666">You can close this tab and return to your terminal.</p>
67	    </div>
68	    <script>setTimeout(()=>window.close(),2000)</script>
69	  </body>
70	</html>`;
71	}
72	
73	function errorHtml(message: string): string {
74	  return `<!doctype html>
75	<html>
76	  <head><title>Connection Failed</title></head>
77	  <body style="font-family:system-ui;display:flex;align-items:center;justify-content:center;height:100vh;margin:0;background:#fafafa">
78	    <div style="text-align:center">
79	      <div style="font-size:48px;margin-bottom:16px">&#10007;</div>
80	      <h1 style="margin:0 0 8px">Connection Failed</h1>
81	      <p style="color:#666">${message}</p>
82	      <p style="color:#999;font-size:14px">Close this tab and try again in your terminal.</p>
83	    </div>
84	  </body>
85	</html>`;
86	}
