88	// ── Redirect Helpers ──
89	
90	function buildRedirectForCompletion(
91	  stateData: Record<string, string>,
92	  providerName: SourceType,
93	  opts: { reactivated?: boolean; setupAction?: string }
94	): CallbackProcessResult {
95	  const redirectTo = stateData.redirectTo;
96	
97	  if (redirectTo === "inline") {
98	    return { kind: "inline_html", html: successHtml(providerName) };
99	  }
100	
101	  if (redirectTo) {
102	    const redirectUrl = new URL(redirectTo);
103	    if (opts.reactivated) {
